import{_ as a,a as d,b as e,c as r}from"./chunks/查询额度成功.BYPQR2qF.js";import{_ as n,o as i,c as l,a2 as o}from"./chunks/framework.DnrXFDHb.js";const A=JSON.parse('{"title":"新增 WebDAV 儲存渠道","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/upload/webdav.md","filePath":"zh-TW/upload/webdav.md","lastUpdated":1781962217000}'),s={name:"zh-TW/upload/webdav.md"};function h(p,t,b,c,m,u){return i(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="新增-webdav-儲存渠道" tabindex="-1">新增 WebDAV 儲存渠道 <a class="header-anchor" href="#新增-webdav-儲存渠道" aria-label="Permalink to &quot;新增 WebDAV 儲存渠道&quot;">​</a></h1><h2 id="適合什麼情境" tabindex="-1">適合什麼情境 <a class="header-anchor" href="#適合什麼情境" aria-label="Permalink to &quot;適合什麼情境&quot;">​</a></h2><ul><li>你有 NAS、雲端硬碟或物件儲存服務提供 WebDAV 端點。</li><li>你想把上傳圖片存到自己的 WebDAV 目錄。</li><li>你希望設定與憑證存在 D1 的 <code>upload_channels</code> 表，不長期暴露在前端。</li></ul><h2 id="新增前要準備什麼" tabindex="-1">新增前要準備什麼 <a class="header-anchor" href="#新增前要準備什麼" aria-label="Permalink to &quot;新增前要準備什麼&quot;">​</a></h2><table tabindex="0"><thead><tr><th>需要準備</th><th>用途</th></tr></thead><tbody><tr><td>WebDAV Endpoint</td><td>服務端 WebDAV 位址，例如 <code>https://nas.example.com/dav</code></td></tr><tr><td>使用者名稱</td><td>登入 WebDAV 服務</td></tr><tr><td>密碼</td><td>登入 WebDAV 服務，建議用應用程式密碼</td></tr><tr><td>儲存目錄</td><td>檔案存放目錄，預設 <code>imgbed</code></td></tr></tbody></table><h2 id="入口位置" tabindex="-1">入口位置 <a class="header-anchor" href="#入口位置" aria-label="Permalink to &quot;入口位置&quot;">​</a></h2><ol><li>進入系統設定。</li><li>打開上傳設定。</li><li>點「新增渠道」。</li><li>選擇 <code>WebDAV</code>。</li></ol><h2 id="欄位說明" tabindex="-1">欄位說明 <a class="header-anchor" href="#欄位說明" aria-label="Permalink to &quot;欄位說明&quot;">​</a></h2><table tabindex="0"><thead><tr><th>欄位</th><th>作用</th><th>是否必填</th></tr></thead><tbody><tr><td>渠道名稱</td><td>用來辨識這個 WebDAV 渠道，例如 <code>nas</code> 或 <code>koofr</code></td><td>是</td></tr><tr><td>Endpoint</td><td>完整 WebDAV 位址，包含 <code>https://</code></td><td>是</td></tr><tr><td>使用者名稱</td><td>WebDAV 登入帳號</td><td>是</td></tr><tr><td>密碼</td><td>WebDAV 登入密碼或應用程式密碼</td><td>是</td></tr><tr><td>儲存目錄</td><td>檔案存放目錄，預設 <code>imgbed</code></td><td>否</td></tr></tbody></table><p>如果服務支援應用程式密碼，建議使用應用程式密碼，不要直接使用主帳號密碼。</p><p><img src="'+a+'" alt="建立應用程式密碼" loading="lazy"></p><p><img src="'+d+'" alt="記下新的應用程式密碼" loading="lazy"></p><h2 id="回-imgbed-填寫設定" tabindex="-1">回 ImgBed 填寫設定 <a class="header-anchor" href="#回-imgbed-填寫設定" aria-label="Permalink to &quot;回 ImgBed 填寫設定&quot;">​</a></h2><table tabindex="0"><thead><tr><th>欄位</th><th>填寫方式</th></tr></thead><tbody><tr><td>Endpoint</td><td>WebDAV 服務提供的完整網址</td></tr><tr><td>使用者名稱</td><td>WebDAV 帳號</td></tr><tr><td>密碼</td><td>WebDAV 密碼或應用程式密碼</td></tr><tr><td>儲存目錄</td><td>預設 <code>imgbed</code>，也可以改成自己的目錄</td></tr></tbody></table><p><img src="'+e+'" alt="填寫設定" loading="lazy"></p><h2 id="大檔案處理方式" tabindex="-1">大檔案處理方式 <a class="header-anchor" href="#大檔案處理方式" aria-label="Permalink to &quot;大檔案處理方式&quot;">​</a></h2><p>WebDAV 渠道目前使用真實工作階段式分段上傳。</p><p>小檔案會直接以完整檔案上傳；大於 64 MiB 的檔案會自動切成約 10 MiB 的分段，存到遠端分段目錄。</p><p>WebDAV 服務不需要支援 partial update 或 offset 寫入。ImgBed 不會在遠端合併成單一大檔，而是記錄分段清單，讀取時再依序組合回完整內容。</p><table tabindex="0"><thead><tr><th>檔案大小</th><th>上傳方式</th><th>遠端儲存形式</th></tr></thead><tbody><tr><td>64 MiB 以下</td><td>一般上傳</td><td>一個完整檔案</td></tr><tr><td>大於 64 MiB</td><td>分段上傳</td><td>分段目錄內多個 chunk 檔</td></tr></tbody></table><p>分段目錄只影響遠端儲存結構，不會改變使用者拿到的 <code>/file/...</code> 連結。</p><h2 id="新增完成後怎麼檢查" tabindex="-1">新增完成後怎麼檢查 <a class="header-anchor" href="#新增完成後怎麼檢查" aria-label="Permalink to &quot;新增完成後怎麼檢查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>檢查項目</th><th>檢查方式</th></tr></thead><tbody><tr><td>渠道卡片是否出現</td><td>儲存後，上傳設定頁應顯示 WebDAV 渠道</td></tr><tr><td>詳情是否正確</td><td>Endpoint、使用者名稱、儲存目錄等資訊正確</td></tr><tr><td>小檔案上傳</td><td>上傳測試圖片後，WebDAV 目錄裡看得到檔案</td></tr><tr><td>大檔案規則</td><td>大於 64 MiB 的檔案會走分段上傳並建立分段目錄</td></tr><tr><td>容量查詢</td><td>若服務支援容量資訊，查詢會顯示已用與總容量</td></tr></tbody></table><p><img src="'+r+`" alt="查詢容量成功" loading="lazy"></p><h2 id="常見問題" tabindex="-1">常見問題 <a class="header-anchor" href="#常見問題" aria-label="Permalink to &quot;常見問題&quot;">​</a></h2><h3 id="為什麼大檔案會產生分段目錄" tabindex="-1">為什麼大檔案會產生分段目錄？ <a class="header-anchor" href="#為什麼大檔案會產生分段目錄" aria-label="Permalink to &quot;為什麼大檔案會產生分段目錄？&quot;">​</a></h3><p>這是目前的大檔案儲存方式。檔案不會在遠端合併成單一大檔，而是由 ImgBed 記錄分段清單，存取時再讀取分段組合。</p><h3 id="上傳失敗先檢查什麼" tabindex="-1">上傳失敗先檢查什麼？ <a class="header-anchor" href="#上傳失敗先檢查什麼" aria-label="Permalink to &quot;上傳失敗先檢查什麼？&quot;">​</a></h3><p>先檢查 Endpoint、帳號、密碼和儲存目錄，再確認 WebDAV 服務允許建立目錄、寫入檔案和讀取檔案。</p><h3 id="容量查詢失敗代表不能上傳嗎" tabindex="-1">容量查詢失敗代表不能上傳嗎？ <a class="header-anchor" href="#容量查詢失敗代表不能上傳嗎" aria-label="Permalink to &quot;容量查詢失敗代表不能上傳嗎？&quot;">​</a></h3><p>不一定。有些 WebDAV 服務不支援或限制容量資訊。只要小檔案上傳正常，通常仍可使用。</p><h2 id="快速流程" tabindex="-1">快速流程 <a class="header-anchor" href="#快速流程" aria-label="Permalink to &quot;快速流程&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>準備 WebDAV Endpoint、帳號和密碼</span></span>
<span class="line"><span>-&gt; 打開上傳設定</span></span>
<span class="line"><span>-&gt; 新增渠道</span></span>
<span class="line"><span>-&gt; 選 WebDAV</span></span>
<span class="line"><span>-&gt; 填 Endpoint / 帳號 / 密碼</span></span>
<span class="line"><span>-&gt; 儲存目錄預設 imgbed</span></span>
<span class="line"><span>-&gt; 儲存</span></span>
<span class="line"><span>-&gt; 查詢容量</span></span>
<span class="line"><span>-&gt; 上傳測試圖片</span></span></code></pre></div>`,33)])])}const D=n(s,[["render",h]]);export{A as __pageData,D as default};
